  ATK_ROLE_LABEL(28),
  ATK_ROLE_LAYERED_PANE(29),
  ATK_ROLE_LIST(30),
  ATK_ROLE_LIST_ITEM(31),
  ATK_ROLE_MENU(32),
  ATK_ROLE_MENU_BAR(33),
  ATK_ROLE_MENU_ITEM(34),
  ATK_ROLE_OPTION_PANE(35),
  ATK_ROLE_PAGE_TAB(36),
  ATK_ROLE_PAGE_TAB_LIST(37),
  ATK_ROLE_PANEL(38),
  ATK_ROLE_PASSWORD_TEXT(39),
  ATK_ROLE_POPUP_MENU(40),
  ATK_ROLE_PROGRESS_BAR(41),
  ATK_ROLE_PUSH_BUTTON(42),
  ATK_ROLE_RADIO_BUTTON(43),
  ATK_ROLE_RADIO_MENU_ITEM(44),
  ATK_ROLE_ROOT_PANE(45),
  ATK_ROLE_ROW_HEADER(46),
  ATK_ROLE_SCROLL_BAR(47),
  ATK_ROLE_SCROLL_PANE(48),
  ATK_ROLE_SEPARATOR(49),
  ATK_ROLE_SLIDER(50),
  ATK_ROLE_SPLIT_PANE(51),
  ATK_ROLE_SPIN_BUTTON(52),
  ATK_ROLE_STATUSBAR(53),
  ATK_ROLE_TABLE(54),
  ATK_ROLE_TABLE_CELL(55),
  ATK_ROLE_TABLE_COLUMN_HEADER(56),
  ATK_ROLE_TABLE_ROW_HEADER(57),
  ATK_ROLE_TEAR_OFF_MENU_ITEM(58),
  ATK_ROLE_TERMINAL(59),
  ATK_ROLE_TEXT(60),
  ATK_ROLE_TOGGLE_BUTTON(61),
  ATK_ROLE_TOOL_BAR(62),
  ATK_ROLE_TOOL_TIP(63),
  ATK_ROLE_TREE(64),
  ATK_ROLE_TREE_TABLE(65),
  ATK_ROLE_UNKNOWN(66),
  ATK_ROLE_VIEWPORT(67),
  ATK_ROLE_WINDOW(68),
  ATK_ROLE_HEADER(69),
  ATK_ROLE_FOOTER(70),
  ATK_ROLE_PARAGRAPH(71),
  ATK_ROLE_RULER(72),
  ATK_ROLE_APPLICATION(73),
  ATK_ROLE_AUTOCOMPLETE(74),
  ATK_ROLE_EDITBAR(75),
  ATK_ROLE_EMBEDDED(76),
  ATK_ROLE_ENTRY(77),
  ATK_ROLE_CHART(78),
  ATK_ROLE_CAPTION(79),
  ATK_ROLE_DOCUMENT_FRAME(80),
  ATK_ROLE_HEADING(81),
  ATK_ROLE_PAGE(82),
  ATK_ROLE_SECTION(83),
  ATK_ROLE_REDUNDANT_OBJECT(84),
  ATK_ROLE_FORM(85),
  ATK_ROLE_LINK(86),
  ATK_ROLE_INPUT_METHOD_WINDOW(87),
  ATK_ROLE_TABLE_ROW(88),
  ATK_ROLE_TREE_ITEM(89),
  ATK_ROLE_DOCUMENT_SPREADSHEET(90),
  ATK_ROLE_DOCUMENT_PRESENTATION(91),
  ATK_ROLE_DOCUMENT_TEXT(92),
  ATK_ROLE_DOCUMENT_WEB(93),
  ATK_ROLE_DOCUMENT_EMAIL(94),
  ATK_ROLE_COMMENT(95),
  ATK_ROLE_LIST_BOX(96),
  ATK_ROLE_GROUPING(97),
  ATK_ROLE_IMAGE_MAP(98),
  ATK_ROLE_NOTIFICATION(99),
  ATK_ROLE_INFO_BAR(100),
  ATK_ROLE_LEVEL_BAR(101),
  ATK_ROLE_TITLE_BAR(102),
  ATK_ROLE_BLOCK_QUOTE(103),
  ATK_ROLE_AUDIO(104),
  ATK_ROLE_VIDEO(105),
  ATK_ROLE_DEFINITION(106),
  ATK_ROLE_ARTICLE(107),
  ATK_ROLE_LANDMARK(108),
  ATK_ROLE_LOG(109),
  ATK_ROLE_MARQUEE(110),
  ATK_ROLE_MATH(111),
  ATK_ROLE_RATING(112),
  ATK_ROLE_TIMER(113),
  ATK_ROLE_DESCRIPTION_LIST(114),
  ATK_ROLE_DESCRIPTION_TERM(115),
  ATK_ROLE_DESCRIPTION_VALUE(116),
  ATK_ROLE_STATIC(117),
  ATK_ROLE_MATH_FRACTION(118),
  ATK_ROLE_MATH_ROOT(119),
  ATK_ROLE_SUBSCRIPT(120),
  ATK_ROLE_SUPERSCRIPT(121),
  ATK_ROLE_FOOTNOTE(122),
  ATK_ROLE_CONTENT_DELETION(123),
  ATK_ROLE_CONTENT_INSERTION(124),
  ATK_ROLE_MARK(125),
  ATK_ROLE_SUGGESTION(126),
  ATK_ROLE_PUSH_BUTTON_MENU(127),
  ATK_ROLE_LAST_DEFINED(128);

  final int value;
  const AtkRole(this.value);

  static AtkRole fromValue(int value) => switch (value) {
    0 => ATK_ROLE_INVALID,
    1 => ATK_ROLE_ACCEL_LABEL,
    2 => ATK_ROLE_ALERT,
    3 => ATK_ROLE_ANIMATION,
    4 => ATK_ROLE_ARROW,
    5 => ATK_ROLE_CALENDAR,
    6 => ATK_ROLE_CANVAS,
    7 => ATK_ROLE_CHECK_BOX,
    8 => ATK_ROLE_CHECK_MENU_ITEM,
    9 => ATK_ROLE_COLOR_CHOOSER,
    10 => ATK_ROLE_COLUMN_HEADER,
    11 => ATK_ROLE_COMBO_BOX,
    12 => ATK_ROLE_DATE_EDITOR,
    13 => ATK_ROLE_DESKTOP_ICON,
    14 => ATK_ROLE_DESKTOP_FRAME,
    15 => ATK_ROLE_DIAL,
    16 => ATK_ROLE_DIALOG,
    17 => ATK_ROLE_DIRECTORY_PANE,
    18 => ATK_ROLE_DRAWING_AREA,
    19 => ATK_ROLE_FILE_CHOOSER,
    20 => ATK_ROLE_FILLER,
    21 => ATK_ROLE_FONT_CHOOSER,
    22 => ATK_ROLE_FRAME,
    23 => ATK_ROLE_GLASS_PANE,
    24 => ATK_ROLE_HTML_CONTAINER,
    25 => ATK_ROLE_ICON,
    26 => ATK_ROLE_IMAGE,
    27 => ATK_ROLE_INTERNAL_FRAME,
    28 => ATK_ROLE_LABEL,
    29 => ATK_ROLE_LAYERED_PANE,
    30 => ATK_ROLE_LIST,
    31 => ATK_ROLE_LIST_ITEM,
    32 => ATK_ROLE_MENU,
    33 => ATK_ROLE_MENU_BAR,
    34 => ATK_ROLE_MENU_ITEM,
    35 => ATK_ROLE_OPTION_PANE,
    36 => ATK_ROLE_PAGE_TAB,
    37 => ATK_ROLE_PAGE_TAB_LIST,
    38 => ATK_ROLE_PANEL,
    39 => ATK_ROLE_PASSWORD_TEXT,
    40 => ATK_ROLE_POPUP_MENU,
    41 => ATK_ROLE_PROGRESS_BAR,
    42 => ATK_ROLE_PUSH_BUTTON,
    43 => ATK_ROLE_RADIO_BUTTON,
    44 => ATK_ROLE_RADIO_MENU_ITEM,
    45 => ATK_ROLE_ROOT_PANE,
    46 => ATK_ROLE_ROW_HEADER,
    47 => ATK_ROLE_SCROLL_BAR,
    48 => ATK_ROLE_SCROLL_PANE,
    49 => ATK_ROLE_SEPARATOR,
    50 => ATK_ROLE_SLIDER,
    51 => ATK_ROLE_SPLIT_PANE,
    52 => ATK_ROLE_SPIN_BUTTON,
    53 => ATK_ROLE_STATUSBAR,
    54 => ATK_ROLE_TABLE,
    55 => ATK_ROLE_TABLE_CELL,
    56 => ATK_ROLE_TABLE_COLUMN_HEADER,
    57 => ATK_ROLE_TABLE_ROW_HEADER,
    58 => ATK_ROLE_TEAR_OFF_MENU_ITEM,
    59 => ATK_ROLE_TERMINAL,
    60 => ATK_ROLE_TEXT,
    61 => ATK_ROLE_TOGGLE_BUTTON,
    62 => ATK_ROLE_TOOL_BAR,
    63 => ATK_ROLE_TOOL_TIP,
