  const GtkTreeViewColumnSizing(this.value);

  static GtkTreeViewColumnSizing fromValue(int value) => switch (value) {
    0 => GTK_TREE_VIEW_COLUMN_GROW_ONLY,
    1 => GTK_TREE_VIEW_COLUMN_AUTOSIZE,
    2 => GTK_TREE_VIEW_COLUMN_FIXED,
    _ => throw ArgumentError(
      "Unknown value for GtkTreeViewColumnSizing: $value",
    ),
  };
}

