/// GtkTextSearchFlags:
/// @GTK_TEXT_SEARCH_VISIBLE_ONLY: Search only visible data. A search match may
/// have invisible text interspersed.
/// @GTK_TEXT_SEARCH_TEXT_ONLY: Search only text. A match may have pixbufs or
/// child widgets mixed inside the matched range.
/// @GTK_TEXT_SEARCH_CASE_INSENSITIVE: The text will be matched regardless of
/// what case it is in.
///
/// Flags affecting how a search is done.
///
/// If neither #GTK_TEXT_SEARCH_VISIBLE_ONLY nor #GTK_TEXT_SEARCH_TEXT_ONLY are
/// enabled, the match must be exact; the special 0xFFFC character will match
/// embedded pixbufs or child widgets.
enum GtkTextSearchFlags {
  GTK_TEXT_SEARCH_VISIBLE_ONLY(1),
  GTK_TEXT_SEARCH_TEXT_ONLY(2),
  GTK_TEXT_SEARCH_CASE_INSENSITIVE(4);

  final int value;
  const GtkTextSearchFlags(this.value);

  static GtkTextSearchFlags fromValue(int value) => switch (value) {
    1 => GTK_TEXT_SEARCH_VISIBLE_ONLY,
    2 => GTK_TEXT_SEARCH_TEXT_ONLY,
    4 => GTK_TEXT_SEARCH_CASE_INSENSITIVE,
    _ => throw ArgumentError("Unknown value for GtkTextSearchFlags: $value"),
  };
}

