/// GtkUIManagerItemType:
/// @GTK_UI_MANAGER_AUTO: Pick the type of the UI element according to context.
/// @GTK_UI_MANAGER_MENUBAR: Create a menubar.
/// @GTK_UI_MANAGER_MENU: Create a menu.
/// @GTK_UI_MANAGER_TOOLBAR: Create a toolbar.
/// @GTK_UI_MANAGER_PLACEHOLDER: Insert a placeholder.
/// @GTK_UI_MANAGER_POPUP: Create a popup menu.
/// @GTK_UI_MANAGER_MENUITEM: Create a menuitem.
/// @GTK_UI_MANAGER_TOOLITEM: Create a toolitem.
/// @GTK_UI_MANAGER_SEPARATOR: Create a separator.
/// @GTK_UI_MANAGER_ACCELERATOR: Install an accelerator.
/// @GTK_UI_MANAGER_POPUP_WITH_ACCELS: Same as %GTK_UI_MANAGER_POPUP, but the
/// actions’ accelerators are shown.
///
/// These enumeration values are used by gtk_ui_manager_add_ui() to determine
/// what UI element to create.
///
/// Deprecated: 3.10
enum GtkUIManagerItemType {
  GTK_UI_MANAGER_AUTO(0),
  GTK_UI_MANAGER_MENUBAR(1),
  GTK_UI_MANAGER_MENU(2),
  GTK_UI_MANAGER_TOOLBAR(4),
  GTK_UI_MANAGER_PLACEHOLDER(8),
  GTK_UI_MANAGER_POPUP(16),
  GTK_UI_MANAGER_MENUITEM(32),
  GTK_UI_MANAGER_TOOLITEM(64),
  GTK_UI_MANAGER_SEPARATOR(128),
  GTK_UI_MANAGER_ACCELERATOR(256),
  GTK_UI_MANAGER_POPUP_WITH_ACCELS(512);

  final int value;
  const GtkUIManagerItemType(this.value);

  static GtkUIManagerItemType fromValue(int value) => switch (value) {
    0 => GTK_UI_MANAGER_AUTO,
    1 => GTK_UI_MANAGER_MENUBAR,
    2 => GTK_UI_MANAGER_MENU,
    4 => GTK_UI_MANAGER_TOOLBAR,
    8 => GTK_UI_MANAGER_PLACEHOLDER,
    16 => GTK_UI_MANAGER_POPUP,
    32 => GTK_UI_MANAGER_MENUITEM,
    64 => GTK_UI_MANAGER_TOOLITEM,
    128 => GTK_UI_MANAGER_SEPARATOR,
    256 => GTK_UI_MANAGER_ACCELERATOR,
    512 => GTK_UI_MANAGER_POPUP_WITH_ACCELS,
    _ => throw ArgumentError("Unknown value for GtkUIManagerItemType: $value"),
  };
}

